const STORAGE_KEY    = "lydex_claims_v4";
const ADMINS_KEY     = "lydex_admins_v4";
const DEFAULT_ADMINS = [
  "y.elhint@lydex-se.ma",
  "m.moubsit@lydex-se.ma",
  "o.benbrahim@lydex-se.ma",
  "h.qorte@lydex-se.ma",
];

const CYAN       = "#29ABD4";
const CYAN_DARK  = "#1A8FB5";
