const ALL_ZONES = BATIMENTS.flatMap(b => b.zones);

const PRIORITIES = [
  {id:"low",   label:"Faible", color:"#059669"},
  {id:"medium",label:"Moyen",  color:"#D97706"},
  {id:"high",  label:"Urgent", color:"#DC2626"},
];

const STATUS_CONFIG = {
  pending:     {label:"En attente",  color:"#D97706", bg:"#FEF3C7"},
  in_progress: {label:"En cours",    color:CYAN,      bg:CYAN_LIGHT},
  resolved:    {label:"Résolu",      color:"#059669", bg:"#D1FAE5"},
  rejected:    {label:"Rejeté",      color:"#DC2626", bg:"#FEE2E2"},
};

const isValidEmail = (e) => e.toLowerCase().endsWith("@lydex-se.ma");
const isAdmin      = (e, admins) => admins.map(a=>a.toLowerCase()).includes(e.toLowerCase());
const generateId   = () => "CLM-" + Date.now().toString(36).toUpperCase();
const formatDate   = (iso) => new Date(iso).toLocaleDateString("fr-MA",{
  day:"2-digit",month:"short",year:"numeric",hour:"2-digit",minute:"2-digit",
});

// ─── Envoi email via Web3Forms (4 admins) ────────────────────────────────────
const ADMIN_EMAILS = [
  "y.elhint@lydex-se.ma",
  "m.moubsit@lydex-se.ma",
  "o.benbrahim@lydex-se.ma",
  "h.qorte@lydex-se.ma",
];

async function sendEmailNotification(claim) {
  try {
    const cat      = CATEGORIES.find(c=>c.id===claim.category);
    const zone     = ALL_ZONES.find(z=>z.id===claim.zone)?.label;
    const priority = PRIORITIES.find(p=>p.id===claim.priority)?.label;

    const body = `
Réclamations Lydex — Nouvelle réclamation

━━━━━━━━━━━━━━━━━━━━━━━━━━━━
Référence  : ${claim.id}
Soumis par : ${claim.email}
Zone       : ${zone}
Bâtiment   : ${claim.batiment || "—"}
Catégorie  : ${cat?.label}
Priorité   : ${priority}
Titre      : ${claim.title}
Date       : ${formatDate(claim.createdAt)}
━━━━━━━━━━━━━━━━━━━━━━━━━━━━

Description :
${claim.description}

━━━━━━━━━━━━━━━━━━━━━━━━━━━━
👉 Voir sur l'application : ${APP_URL}
━━━━━━━━━━━━━━━━━━━━━━━━━━━━
    `.trim();

    // Envoie un email à chaque admin simultanément
    await Promise.all(ADMIN_EMAILS.map(adminEmail =>
      fetch("https://api.web3forms.com/submit", {
        method: "POST",
        headers: {"Content-Type":"application/json", "Accept":"application/json"},
        body: JSON.stringify({
          access_key:  WEB3FORMS_KEY,
          from_name:   "Réclamations Lydex",
          subject:     `🔔 Nouvelle réclamation — ${zone} — ${cat?.label}`,
          message:     body,
          email:       adminEmail,
        }),
      }).catch(e => console.warn("Web3Forms error:", e))
    ));
  } catch(e) { console.warn("Web3Forms error:", e); }
}

// ─── Logo (intégré en base64) ────────────────────────────────────────────────
const LOGO_B64 = "data:image/png;base64,";

// Logo sur fond sombre → fond blanc rendu transparent via CSS
function LydexLogoLight({ height=44 }) {
  return (
    <div style={{
      height, display:"flex", alignItems:"center", justifyContent:"center",
      background:"#fff", borderRadius:10, padding:"4px 10px",
    }}>
      <img src={LOGO_B64} alt="Lycée d'Excellence de Rabat"
        style={{ height:height*0.75, width:"auto", objectFit:"contain" }}
      />
    </div>
  );
}

// Logo sur fond blanc → affiché directement
function LydexLogoDark({ height=36 }) {
  return (
    <img src={LOGO_B64} alt="Lycée d'Excellence de Rabat"
      style={{ height, width:"auto", objectFit:"contain" }}
    />
  );
}

function Badge({ status }) {
  const c = STATUS_CONFIG[status];
  return (
    <span style={{
      background:c.bg, color:c.color, border:`1px solid ${c.color}50`,
      borderRadius:20, padding:"3px 10px", fontSize:11, fontWeight:700, whiteSpace:"nowrap",
    }}>{c.label}</span>
  );
}

// ─── LOGIN ────────────────────────────────────────────────────────────────────
function LoginPage({ onLogin }) {
  const [email,   setEmail]   = useState("");
  const [error,   setError]   = useState("");
  const [loading, setLoading] = useState(false);
  const [focused, setFocused] = useState(false);

  const submit = () => {
    setError("");
    if (!email.trim()) return setError("Veuillez entrer votre adresse email.");
    if (!isValidEmail(email)) return setError("Seules les adresses @lydex-se.ma sont autorisées.");
    setLoading(true);
    setTimeout(()=>{ setLoading(false); onLogin(email.trim().toLowerCase()); }, 700);
  };

  return (
    <div style={{
      minHeight:"100vh",
      background:`linear-gradient(160deg,${DARK} 0%,#2A2A3E 50%,#252540 100%)`,
      display:"flex", alignItems:"center", justifyContent:"center",
      fontFamily:"'Segoe UI',system-ui,sans-serif", padding:20,
    }}>
      <div style={{position:"fixed",inset:0,opacity:0.04,backgroundImage:"radial-gradient(circle,#fff 1px,transparent 1px)",backgroundSize:"28px 28px",pointerEvents:"none"}}/>
      <div style={{position:"fixed",top:"10%",left:"50%",transform:"translateX(-50%)",width:500,height:250,borderRadius:"50%",background:`radial-gradient(ellipse,${CYAN}25 0%,transparent 70%)`,pointerEvents:"none"}}/>

      <div style={{background:"#fff",borderRadius:24,padding:"44px 36px",width:"100%",maxWidth:420,boxShadow:"0 32px 80px rgba(0,0,0,0.5)",animation:"fadeUp 0.5s cubic-bezier(.22,1,.36,1)"}}>
        <div style={{textAlign:"center",marginBottom:28}}>
          <div style={{background:DARK,borderRadius:16,padding:"18px 28px",display:"inline-flex",alignItems:"center",justifyContent:"center",marginBottom:18,boxShadow:`0 6px 20px ${DARK}60`}}>
            <LydexLogoLight height={52}/>
          </div>
          <h1 style={{margin:0,fontSize:21,fontWeight:800,color:DARK}}>Portail Réclamations</h1>
          <p style={{margin:"6px 0 0",color:"#6B7280",fontSize:13.5}}>Lycée d'Excellence de Rabat</p>
        </div>

        <label style={{display:"block",fontSize:11.5,fontWeight:700,color:"#374151",marginBottom:6,textTransform:"uppercase",letterSpacing:"0.05em"}}>
          Entrez votre adresse email Lydex
        </label>
        <input type="email" value={email}
          onChange={e=>{setEmail(e.target.value);setError("");}}
          onFocus={()=>setFocused(true)} onBlur={()=>setFocused(false)}
          onKeyDown={e=>e.key==="Enter"&&submit()}
          placeholder="prenom.nom@lydex-se.ma"
          style={{width:"100%",padding:"13px 14px",borderRadius:11,fontSize:14,border:`2px solid ${error?"#DC2626":focused?CYAN:BORDER}`,outline:"none",boxSizing:"border-box",background:"#FAFAFA",color:DARK,transition:"border 0.2s"}}
        />
        {error && <p style={{margin:"6px 0 0",color:"#DC2626",fontSize:12}}>⚠ {error}</p>}

        <div style={{background:CYAN_LIGHT,border:`1px solid ${CYAN}40`,borderRadius:9,padding:"9px 13px",margin:"14px 0 18px",fontSize:12,color:CYAN_DARK,display:"flex",gap:7}}>
          <span>ℹ️</span>
          <span>Accès réservé aux <strong>élèves et personnels</strong> avec un email <strong>@lydex-se.ma</strong></span>
        </div>

        <button onClick={submit} disabled={loading} style={{width:"100%",padding:"14px",borderRadius:11,border:"none",background:loading?"#9CA3AF":`linear-gradient(135deg,${CYAN},${CYAN_DARK})`,color:"#fff",fontSize:14.5,fontWeight:700,cursor:loading?"not-allowed":"pointer",boxShadow:`0 4px 16px ${CYAN}50`}}>
          {loading?"Connexion…":"Accéder →"}
        </button>

        <p style={{textAlign:"center",marginTop:18,fontSize:11,color:"#9CA3AF"}}>
          © 2026 Lycée d'Excellence de Rabat — Tous droits réservés
        </p>
      </div>
    </div>
  );
}

// ─── CLAIM FORM ───────────────────────────────────────────────────────────────
function ClaimForm({ user, preZone, onSuccess }) {
  const [step,        setStep]        = useState(1);
  const [category,    setCategory]    = useState("");
  const [batiment,    setBatiment]    = useState("");
  const [zone,        setZone]        = useState(preZone||"");
  const [priority,    setPriority]    = useState("medium");
  const [title,       setTitle]       = useState("");
  const [description, setDescription] = useState("");
  const [photo,       setPhoto]       = useState(null);
  const [photoPreview,setPhotoPreview]= useState(null);
  const [submitting,  setSubmitting]  = useState(false);
  const fileRef = useRef();

  const filteredZones    = batiment?(BATIMENTS.find(b=>b.group===batiment)?.zones||[]):ALL_ZONES;
  const selectedBatLabel = BATIMENTS.find(b=>b.zones.some(z=>z.id===zone))?.group||batiment||"";
  const cat       = CATEGORIES.find(c=>c.id===category);
  const canNext   = category && zone;
  const canSubmit = canNext && title.trim().length>=5 && description.trim().length>=10;

  const handlePhoto = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    if (file.size > 5*1024*1024) return alert("Photo trop lourde (max 5 Mo)");
    setPhoto(file);
    const reader = new FileReader();
    reader.onload = ev => setPhotoPreview(ev.target.result);
    reader.readAsDataURL(file);
  };

  const handleSubmit = async () => {
    if (!canSubmit) return;
    setSubmitting(true);
    const claim = {
      id:generateId(), category, zone, batiment:selectedBatLabel,
      priority, title:title.trim(), description:description.trim(),
      photo: photoPreview || null,
      email:user, status:"pending",
      createdAt:new Date().toISOString(), updatedAt:new Date().toISOString(),
      adminNote:"",
    };
    const claims = loadJSON(STORAGE_KEY,[]);
    saveJSON(STORAGE_KEY,[claim,...claims]);
    await sendEmailNotification(claim);
    setSubmitting(false);
    onSuccess(claim);
  };

  const inp = {width:"100%",padding:"11px 13px",borderRadius:10,border:`2px solid ${BORDER}`,fontSize:13.5,outline:"none",boxSizing:"border-box",background:"#FAFAFA",fontFamily:"inherit"};

  return (
    <div style={{animation:"fadeUp 0.3s ease"}}>
      {/* Steps */}
      <div style={{display:"flex",alignItems:"center",gap:6,marginBottom:24}}>
        {[1,2].map(s=>(
          <div key={s} style={{display:"flex",alignItems:"center",gap:6,flex:s===1?1:"none"}}>
            <div style={{width:28,height:28,borderRadius:"50%",display:"flex",alignItems:"center",justifyContent:"center",fontSize:12,fontWeight:800,background:step>=s?CYAN:BORDER,color:step>=s?"#fff":"#9CA3AF",transition:"all 0.3s"}}>{s}</div>
            <span style={{fontSize:12,fontWeight:step>=s?700:400,color:step>=s?CYAN:"#9CA3AF"}}>{s===1?"Catégorie & Zone":"Détails"}</span>
            {s===1&&<div style={{flex:1,height:2,borderRadius:2,background:step>1?CYAN:BORDER,transition:"all 0.3s"}}/>}
          </div>
        ))}
      </div>

      {step===1&&(
        <>
          <p style={{margin:"0 0 10px",fontSize:11.5,fontWeight:700,color:DARK,textTransform:"uppercase",letterSpacing:"0.05em"}}>Catégorie *</p>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,marginBottom:20}}>
            {CATEGORIES.map(c=>(
              <button key={c.id} onClick={()=>setCategory(c.id)} style={{padding:"12px 10px",borderRadius:11,cursor:"pointer",textAlign:"left",border:`2px solid ${category===c.id?c.color:BORDER}`,background:category===c.id?c.color+"12":"#FAFAFA",transition:"all 0.18s"}}>
                <div style={{fontSize:18}}>{c.icon}</div>
                <div style={{fontWeight:700,fontSize:12,color:category===c.id?c.color:DARK,marginTop:3}}>{c.label}</div>
                <div style={{fontSize:10,color:"#9CA3AF",marginTop:1,lineHeight:1.3}}>{c.desc}</div>
              </button>
            ))}
          </div>

          <p style={{margin:"0 0 8px",fontSize:11.5,fontWeight:700,color:DARK,textTransform:"uppercase",letterSpacing:"0.05em"}}>Bâtiment</p>
          <div style={{display:"flex",flexWrap:"wrap",gap:6,marginBottom:14}}>
            {BATIMENTS.map(b=>(
              <button key={b.group} onClick={()=>{setBatiment(b.group===batiment?"":b.group);setZone("");}} style={{padding:"6px 12px",borderRadius:20,cursor:"pointer",border:`2px solid ${batiment===b.group?CYAN:BORDER}`,background:batiment===b.group?CYAN:"#fff",color:batiment===b.group?"#fff":DARK,fontSize:12,fontWeight:600,transition:"all 0.18s"}}>{b.group}</button>
            ))}
          </div>

          <p style={{margin:"0 0 7px",fontSize:11.5,fontWeight:700,color:DARK,textTransform:"uppercase",letterSpacing:"0.05em"}}>Zone / Emplacement *</p>
          <select value={zone} onChange={e=>setZone(e.target.value)} style={{...inp,marginBottom:20,cursor:"pointer"}}>
            <option value="">— Sélectionner un emplacement —</option>
            {(batiment?filteredZones:ALL_ZONES).map(z=><option key={z.id} value={z.id}>{z.label}</option>)}
          </select>

          <button onClick={()=>canNext&&setStep(2)} style={{width:"100%",padding:"13px",borderRadius:10,border:"none",background:canNext?`linear-gradient(135deg,${CYAN},${CYAN_DARK})`:BORDER,color:canNext?"#fff":"#9CA3AF",fontSize:14,fontWeight:700,cursor:canNext?"pointer":"not-allowed",boxShadow:canNext?`0 4px 14px ${CYAN}40`:"none"}}>Suivant →</button>
        </>
      )}

      {step===2&&(
        <>
          <div style={{display:"flex",alignItems:"center",gap:10,padding:"10px 13px",background:(cat?.color||CYAN)+"10",borderRadius:10,marginBottom:18,border:`1px solid ${(cat?.color||CYAN)}25`}}>
            <span style={{fontSize:22}}>{cat?.icon}</span>
            <div>
              <div style={{fontWeight:700,fontSize:13,color:cat?.color}}>{cat?.label}</div>
              <div style={{fontSize:11.5,color:"#6B7280"}}>{ALL_ZONES.find(z=>z.id===zone)?.label}{selectedBatLabel&&` · ${selectedBatLabel}`}</div>
            </div>
          </div>

          <p style={{margin:"0 0 8px",fontSize:11.5,fontWeight:700,color:DARK,textTransform:"uppercase",letterSpacing:"0.05em"}}>Priorité</p>
          <div style={{display:"flex",gap:7,marginBottom:16}}>
            {PRIORITIES.map(p=>(
              <button key={p.id} onClick={()=>setPriority(p.id)} style={{flex:1,padding:"9px",borderRadius:8,cursor:"pointer",border:`2px solid ${priority===p.id?p.color:BORDER}`,background:priority===p.id?p.color+"15":"#FAFAFA",color:priority===p.id?p.color:"#6B7280",fontSize:12.5,fontWeight:700}}>{p.label}</button>
            ))}
          </div>

          <p style={{margin:"0 0 6px",fontSize:11.5,fontWeight:700,color:DARK,textTransform:"uppercase",letterSpacing:"0.05em"}}>Titre *</p>
          <input value={title} onChange={e=>setTitle(e.target.value)} maxLength={80} placeholder="Ex : Climatiseur en panne, Robinet qui fuit…" style={{...inp,marginBottom:14}}/>

          <p style={{margin:"0 0 6px",fontSize:11.5,fontWeight:700,color:DARK,textTransform:"uppercase",letterSpacing:"0.05em"}}>Description *</p>
          <textarea value={description} onChange={e=>setDescription(e.target.value)} rows={4} maxLength={500} placeholder="Décrivez précisément le problème…" style={{...inp,resize:"vertical",marginBottom:4}}/>
          <div style={{textAlign:"right",fontSize:11,color:"#9CA3AF",marginBottom:16}}>{description.length}/500</div>

          {/* Photo */}
          <p style={{margin:"0 0 8px",fontSize:11.5,fontWeight:700,color:DARK,textTransform:"uppercase",letterSpacing:"0.05em"}}>Photo (optionnel)</p>
          <div
            onClick={()=>fileRef.current.click()}
            style={{
              border:`2px dashed ${photoPreview?CYAN:BORDER}`,
              borderRadius:12, padding:"16px", cursor:"pointer",
              background:photoPreview?CYAN_LIGHT:"#FAFAFA",
              textAlign:"center", marginBottom:20, transition:"all 0.2s",
            }}
          >
            {photoPreview ? (
              <div style={{position:"relative",display:"inline-block"}}>
                <img src={photoPreview} alt="preview" style={{maxWidth:"100%",maxHeight:160,borderRadius:8,display:"block"}}/>
                <button onClick={e=>{e.stopPropagation();setPhoto(null);setPhotoPreview(null);}} style={{position:"absolute",top:-8,right:-8,background:"#DC2626",color:"#fff",border:"none",borderRadius:"50%",width:22,height:22,fontSize:13,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center"}}>✕</button>
              </div>
            ) : (
              <>
                <div style={{fontSize:28,marginBottom:6}}>📷</div>
                <div style={{fontSize:13,color:"#6B7280",fontWeight:600}}>Appuyez pour ajouter une photo</div>
                <div style={{fontSize:11,color:"#9CA3AF",marginTop:3}}>JPG, PNG — max 5 Mo</div>
              </>
            )}
          </div>
          <input ref={fileRef} type="file" accept="image/*" capture="environment" onChange={handlePhoto} style={{display:"none"}}/>

          <div style={{display:"flex",gap:8}}>
            <button onClick={()=>setStep(1)} style={{flex:1,padding:"12px",borderRadius:10,border:`2px solid ${BORDER}`,background:"#fff",color:"#6B7280",fontSize:13.5,fontWeight:600,cursor:"pointer"}}>← Retour</button>
            <button onClick={handleSubmit} disabled={!canSubmit||submitting} style={{flex:2,padding:"12px",borderRadius:10,border:"none",background:canSubmit&&!submitting?`linear-gradient(135deg,${CYAN},${CYAN_DARK})`:BORDER,color:canSubmit&&!submitting?"#fff":"#9CA3AF",fontSize:13.5,fontWeight:700,cursor:canSubmit&&!submitting?"pointer":"not-allowed"}}>
              {submitting?"Envoi en cours…":"Envoyer ✓"}
            </button>
          </div>
        </>
      )}
    </div>
  );
}

// ─── SUCCESS ──────────────────────────────────────────────────────────────────
function SuccessPage({ claim, onNew, onLogout }) {
  const cat = CATEGORIES.find(c=>c.id===claim.category);
  return (
    <div style={{textAlign:"center",padding:"12px 0",animation:"fadeUp 0.4s ease"}}>
      <div style={{width:74,height:74,background:`linear-gradient(135deg,${CYAN},${CYAN_DARK})`,borderRadius:"50%",display:"flex",alignItems:"center",justifyContent:"center",fontSize:32,margin:"0 auto 16px",boxShadow:`0 8px 24px ${CYAN}40`}}>✓</div>
      <h2 style={{margin:"0 0 6px",color:DARK,fontSize:20,fontWeight:800}}>Réclamation envoyée !</h2>
      <p style={{color:"#6B7280",margin:"0 0 20px",fontSize:13.5}}>Votre signalement a été transmis à l'équipe concernée.</p>
      <div style={{background:"#F9FAFB",borderRadius:14,padding:"16px",marginBottom:16,textAlign:"left"}}>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:9}}>
          {[
            {label:"Référence", value:claim.id},
            {label:"Catégorie", value:`${cat?.icon} ${cat?.label}`},
            {label:"Zone",      value:ALL_ZONES.find(z=>z.id===claim.zone)?.label},
            {label:"Priorité",  value:PRIORITIES.find(p=>p.id===claim.priority)?.label},
          ].map(item=>(
            <div key={item.label} style={{background:"#fff",borderRadius:8,padding:"9px 11px"}}>
              <div style={{fontSize:10,color:"#9CA3AF",fontWeight:700,textTransform:"uppercase"}}>{item.label}</div>
              <div style={{fontSize:13,fontWeight:700,color:DARK,marginTop:2}}>{item.value}</div>
            </div>
          ))}
        </div>
      </div>
      <div style={{background:CYAN_LIGHT,border:`1px solid ${CYAN}40`,borderRadius:9,padding:"10px 13px",marginBottom:20,fontSize:12,color:CYAN_DARK}}>
        📬 Un email de confirmation sera envoyé à <strong>{claim.email}</strong>
      </div>
      <div style={{display:"flex",gap:8}}>
        <button onClick={onNew} style={{flex:1,padding:"12px",borderRadius:10,border:`2px solid ${CYAN}`,background:"#fff",color:CYAN,fontSize:13.5,fontWeight:700,cursor:"pointer"}}>+ Nouvelle</button>
        <button onClick={onLogout} style={{flex:1,padding:"12px",borderRadius:10,border:"none",background:`linear-gradient(135deg,${CYAN},${CYAN_DARK})`,color:"#fff",fontSize:13.5,fontWeight:700,cursor:"pointer"}}>Déconnexion</button>
      </div>
    </div>
  );
}

// ─── ADMIN DASHBOARD ──────────────────────────────────────────────────────────
function AdminDashboard({ user, onLogout }) {
  const [admins,       setAdmins]       = useState(()=>loadJSON(ADMINS_KEY,DEFAULT_ADMINS));
  const [claims,       setClaims]       = useState(()=>loadJSON(STORAGE_KEY,[]));
  const [tab,          setTab]          = useState("claims");
  const [filterCat,    setFilterCat]    = useState("all");
  const [filterStatus, setFilterStatus] = useState("all");
  const [filterBat,    setFilterBat]    = useState("all");
  const [selected,     setSelected]     = useState(null);
  const [note,         setNote]         = useState("");
  const [qrZone,       setQrZone]       = useState("RES1");
  const [newAdmin,     setNewAdmin]     = useState("");
  const [adminMsg,     setAdminMsg]     = useState("");

  const refresh = () => setClaims(loadJSON(STORAGE_KEY,[]));

  const filtered = claims.filter(c=>{
    if(filterCat!=="all"&&c.category!==filterCat) return false;
    if(filterStatus!=="all"&&c.status!==filterStatus) return false;
    if(filterBat!=="all"&&c.batiment!==filterBat) return false;
    return true;
  });

  const stats = {
    total:claims.length,
    pending:claims.filter(c=>c.status==="pending").length,
    in_progress:claims.filter(c=>c.status==="in_progress").length,
    resolved:claims.filter(c=>c.status==="resolved").length,
  };

  const updateStatus = (id,status) => {
    const updated=claims.map(c=>c.id===id?{...c,status,adminNote:note,updatedAt:new Date().toISOString()}:c);
    saveJSON(STORAGE_KEY,updated); setClaims(updated);
    if(selected?.id===id) setSelected(prev=>({...prev,status,adminNote:note}));
    setNote("");
  };

  const addAdmin = () => {
    setAdminMsg("");
    const email=newAdmin.trim().toLowerCase();
    if(!email) return setAdminMsg("Entrez un email.");
    if(!isValidEmail(email)) return setAdminMsg("Email doit être @lydex-se.ma");
    if(admins.includes(email)) return setAdminMsg("Admin déjà existant.");
    const updated=[...admins,email]; setAdmins(updated); saveJSON(ADMINS_KEY,updated);
    setNewAdmin(""); setAdminMsg("✓ Admin ajouté !");
  };

  const removeAdmin = (email) => {
    if(email===user) return setAdminMsg("Impossible de vous supprimer vous-même.");
    const updated=admins.filter(a=>a!==email); setAdmins(updated); saveJSON(ADMINS_KEY,updated);
    setAdminMsg("Admin retiré.");
  };

  const appUrl = typeof window!=="undefined"?window.location.href.split("?")[0]:"https://lydex-reclamations-763y.vercel.app";

  return (
    <div style={{animation:"fadeUp 0.3s ease"}}>
      <div style={{background:`linear-gradient(135deg,${DARK},#2A2A3E)`,borderRadius:18,padding:"18px 22px",marginBottom:18,color:"#fff"}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}>
          <div style={{display:"flex",alignItems:"center",gap:14}}>
            <div style={{background:"rgba(255,255,255,0.08)",borderRadius:12,padding:"8px 14px",display:"flex",alignItems:"center"}}>
              <LydexLogoLight height={38}/>
            </div>
            <div>
              <div style={{fontSize:9.5,opacity:0.55,fontWeight:700,textTransform:"uppercase",letterSpacing:"0.12em"}}>Administration</div>
              <div style={{fontWeight:800,fontSize:17,marginTop:1}}>Dashboard Réclamations</div>
              <div style={{fontSize:11,opacity:0.55}}>Lycée d'Excellence de Rabat</div>
            </div>
          </div>
          <button onClick={onLogout} style={{background:"rgba(255,255,255,0.12)",border:"1px solid rgba(255,255,255,0.22)",color:"#fff",padding:"8px 14px",borderRadius:8,cursor:"pointer",fontSize:12.5,fontWeight:600}}>Déconnexion</button>
        </div>
      </div>

      <div style={{display:"flex",gap:4,marginBottom:18,background:"#F3F4F6",borderRadius:10,padding:4}}>
        {[{id:"claims",label:"📋 Réclamations"},{id:"qr",label:"📲 QR Codes"},{id:"admins",label:"👤 Admins"}].map(t=>(
          <button key={t.id} onClick={()=>setTab(t.id)} style={{flex:1,padding:"10px 4px",borderRadius:8,border:"none",cursor:"pointer",fontSize:12.5,background:tab===t.id?"#fff":"transparent",color:tab===t.id?DARK:"#6B7280",fontWeight:tab===t.id?700:500,boxShadow:tab===t.id?"0 1px 4px rgba(0,0,0,0.1)":"none"}}>{t.label}</button>
        ))}
      </div>

      {tab==="claims"&&(
        <>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr 1fr",gap:8,marginBottom:16}}>
            {[
              {label:"Total",      value:stats.total,       color:DARK,      bg:"#EFF6FF"},
              {label:"En attente", value:stats.pending,     color:"#D97706", bg:"#FEF3C7"},
              {label:"En cours",   value:stats.in_progress, color:CYAN,      bg:CYAN_LIGHT},
              {label:"Résolus",    value:stats.resolved,    color:"#059669", bg:"#D1FAE5"},
            ].map(s=>(
              <div key={s.label} style={{background:s.bg,borderRadius:12,padding:"12px 8px",textAlign:"center"}}>
                <div style={{fontSize:22,fontWeight:800,color:s.color}}>{s.value}</div>
                <div style={{fontSize:10,color:s.color,fontWeight:700,marginTop:2}}>{s.label}</div>
              </div>
            ))}
          </div>

          <div style={{display:"flex",gap:6,marginBottom:12,flexWrap:"wrap"}}>
            <select value={filterCat} onChange={e=>setFilterCat(e.target.value)} style={{padding:"7px 10px",borderRadius:7,border:`1.5px solid ${BORDER}`,fontSize:12,color:DARK,background:"#fff",cursor:"pointer"}}>
              <option value="all">Toutes catégories</option>
              {CATEGORIES.map(c=><option key={c.id} value={c.id}>{c.icon} {c.label}</option>)}
            </select>
            <select value={filterStatus} onChange={e=>setFilterStatus(e.target.value)} style={{padding:"7px 10px",borderRadius:7,border:`1.5px solid ${BORDER}`,fontSize:12,color:DARK,background:"#fff",cursor:"pointer"}}>
              <option value="all">Tous statuts</option>
              {Object.entries(STATUS_CONFIG).map(([k,v])=><option key={k} value={k}>{v.label}</option>)}
            </select>
            <select value={filterBat} onChange={e=>setFilterBat(e.target.value)} style={{padding:"7px 10px",borderRadius:7,border:`1.5px solid ${BORDER}`,fontSize:12,color:DARK,background:"#fff",cursor:"pointer"}}>
              <option value="all">Tous bâtiments</option>
              {BATIMENTS.map(b=><option key={b.group} value={b.group}>{b.group}</option>)}
            </select>
            <button onClick={refresh} style={{padding:"7px 12px",borderRadius:7,border:`1.5px solid ${BORDER}`,background:"#fff",cursor:"pointer",fontSize:12,color:"#6B7280"}}>↻ Rafraîchir</button>
          </div>

          {filtered.length===0?(
            <div style={{textAlign:"center",padding:"36px 20px",background:"#F9FAFB",borderRadius:12,color:"#9CA3AF"}}>
              <div style={{fontSize:36,marginBottom:10}}>📭</div>
              <div style={{fontWeight:600,fontSize:14}}>Aucune réclamation</div>
            </div>
          ):(
            <div style={{display:"flex",flexDirection:"column",gap:6}}>
              {filtered.map(c=>{
                const cat=CATEGORIES.find(x=>x.id===c.category);
                return(
                  <div key={c.id} onClick={()=>{setSelected(c);setNote(c.adminNote||"");}} style={{background:"#fff",borderRadius:11,padding:"12px 14px",border:`2px solid ${selected?.id===c.id?CYAN:BORDER}`,cursor:"pointer",transition:"all 0.18s",boxShadow:selected?.id===c.id?`0 0 0 3px ${CYAN}20`:"none"}}>
                    <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",gap:8}}>
                      <div style={{flex:1,minWidth:0}}>
                        <div style={{display:"flex",alignItems:"center",gap:6,marginBottom:3}}>
                          <span style={{fontSize:14}}>{cat?.icon}</span>
                          <span style={{fontWeight:700,fontSize:13,color:DARK,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{c.title}</span>
                          {c.photo&&<span style={{fontSize:11,color:CYAN,fontWeight:700,flexShrink:0}}>📷</span>}
                        </div>
                        <div style={{fontSize:10.5,color:"#9CA3AF"}}>{c.id} · {ALL_ZONES.find(z=>z.id===c.zone)?.label} · {formatDate(c.createdAt)}</div>
                      </div>
                      <Badge status={c.status}/>
                    </div>
                  </div>
                );
              })}
            </div>
          )}

          {selected&&(
            <div style={{marginTop:16,background:"#fff",borderRadius:16,padding:"20px",border:`2px solid ${CYAN}`,animation:"fadeUp 0.25s ease"}}>
              <div style={{display:"flex",justifyContent:"space-between",marginBottom:14}}>
                <h3 style={{margin:0,color:DARK,fontSize:14,fontWeight:800}}>Détail — {selected.id}</h3>
                <button onClick={()=>setSelected(null)} style={{background:"none",border:"none",cursor:"pointer",fontSize:18,color:"#9CA3AF"}}>✕</button>
              </div>
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,marginBottom:12}}>
                {[
                  {label:"Soumis par",  value:selected.email},
                  {label:"Zone",        value:ALL_ZONES.find(z=>z.id===selected.zone)?.label},
                  {label:"Bâtiment",    value:selected.batiment||"—"},
                  {label:"Priorité",    value:PRIORITIES.find(p=>p.id===selected.priority)?.label},
                  {label:"Date",        value:formatDate(selected.createdAt)},
                  {label:"Mise à jour", value:formatDate(selected.updatedAt)},
                ].map(item=>(
                  <div key={item.label} style={{background:"#F9FAFB",borderRadius:8,padding:"8px 10px"}}>
                    <div style={{fontSize:10,color:"#9CA3AF",fontWeight:700}}>{item.label}</div>
                    <div style={{fontSize:12.5,fontWeight:600,color:DARK,marginTop:2}}>{item.value}</div>
                  </div>
                ))}
              </div>
              <div style={{background:"#F9FAFB",borderRadius:8,padding:"10px 12px",marginBottom:12}}>
                <div style={{fontSize:10,color:"#9CA3AF",fontWeight:700,marginBottom:4}}>DESCRIPTION</div>
                <div style={{fontSize:13,color:"#374151",lineHeight:1.6}}>{selected.description}</div>
              </div>
              {selected.photo&&(
                <div style={{marginBottom:12}}>
                  <div style={{fontSize:10,color:"#9CA3AF",fontWeight:700,marginBottom:6}}>PHOTO JOINTE</div>
                  <img src={selected.photo} alt="réclamation" style={{maxWidth:"100%",maxHeight:220,borderRadius:10,border:`1.5px solid ${BORDER}`,display:"block"}}/>
                </div>
              )}
              <textarea value={note} onChange={e=>setNote(e.target.value)} rows={2} placeholder="Note interne de traitement…" style={{width:"100%",padding:"9px 11px",borderRadius:8,border:`1.5px solid ${BORDER}`,fontSize:13,outline:"none",resize:"none",marginBottom:12,boxSizing:"border-box",fontFamily:"inherit"}}/>
              <div style={{display:"flex",gap:6,flexWrap:"wrap"}}>
                {Object.entries(STATUS_CONFIG).map(([k,v])=>(
                  <button key={k} onClick={()=>updateStatus(selected.id,k)} style={{padding:"8px 12px",borderRadius:8,border:`2px solid ${v.color}`,background:selected.status===k?v.color:"#fff",color:selected.status===k?"#fff":v.color,fontSize:11.5,fontWeight:700,cursor:"pointer",transition:"all 0.18s"}}>{v.label}</button>
                ))}
              </div>
            </div>
          )}
        </>
      )}

      {tab==="qr"&&(
        <div style={{animation:"fadeUp 0.3s ease"}}>
          <div style={{background:CYAN_LIGHT,border:`1px solid ${CYAN}40`,borderRadius:10,padding:"11px 14px",marginBottom:16,fontSize:12,color:CYAN_DARK}}>
            💡 Imprimez les QR codes et collez-les dans chaque bâtiment.
          </div>
          <select value={qrZone} onChange={e=>setQrZone(e.target.value)} style={{width:"100%",padding:"11px 13px",borderRadius:10,border:`2px solid ${BORDER}`,fontSize:13.5,color:DARK,background:"#fff",marginBottom:18,cursor:"pointer"}}>
            {BATIMENTS.map(b=>(
              <optgroup key={b.group} label={b.group}>
                {b.zones.map(z=><option key={z.id} value={z.id}>{z.label}</option>)}
              </optgroup>
            ))}
          </select>
          <div style={{textAlign:"center",marginBottom:20}}>
            <div style={{display:"inline-block",background:"#fff",border:`4px solid ${DARK}`,borderRadius:20,padding:"20px 20px 14px",boxShadow:`0 8px 28px ${DARK}20`}}>
              <img src={QR_API(`${appUrl}?zone=${qrZone}`)} alt="QR" style={{width:200,height:200,display:"block"}}/>
              <div style={{marginTop:10,fontWeight:800,color:DARK,fontSize:14}}>{ALL_ZONES.find(z=>z.id===qrZone)?.label}</div>
              <div style={{fontSize:10.5,color:"#9CA3AF",marginTop:3}}>Lycée d'Excellence de Rabat · Réclamations</div>
            </div>
            <div style={{marginTop:12}}>
              <a href={QR_API(`${appUrl}?zone=${qrZone}`)} download={`QR-Lydex-${qrZone}.png`} style={{display:"inline-block",padding:"11px 22px",borderRadius:10,background:`linear-gradient(135deg,${CYAN},${CYAN_DARK})`,color:"#fff",fontSize:13.5,fontWeight:700,textDecoration:"none"}}>⬇ Télécharger PNG</a>
            </div>
          </div>
          <h4 style={{margin:"0 0 12px",color:DARK,fontSize:14}}>Tous les QR codes</h4>
          {BATIMENTS.map(b=>(
            <div key={b.group} style={{marginBottom:14}}>
              <div style={{fontSize:11,fontWeight:700,color:"#6B7280",textTransform:"uppercase",letterSpacing:"0.06em",marginBottom:6}}>{b.group}</div>
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:6}}>
                {b.zones.map(z=>(
                  <a key={z.id} href={QR_API(`${appUrl}?zone=${z.id}`)} download={`QR-${z.id}.png`} style={{padding:"8px 5px",borderRadius:8,background:"#fff",border:`1.5px solid ${BORDER}`,fontSize:10.5,color:CYAN,fontWeight:600,textDecoration:"none",textAlign:"center"}}>⬇ {z.label}</a>
                ))}
              </div>
            </div>
          ))}
        </div>
      )}

      {tab==="admins"&&(
        <div style={{animation:"fadeUp 0.3s ease"}}>
          <div style={{background:"#FFF7ED",border:"1px solid #FED7AA",borderRadius:10,padding:"11px 14px",marginBottom:18,fontSize:12,color:"#92400E"}}>
            ⚠️ Les administrateurs ont accès à toutes les réclamations et reçoivent les notifications email.
          </div>
          <div style={{background:"#D1FAE5",border:"1px solid #6EE7B7",borderRadius:10,padding:"11px 14px",marginBottom:18,fontSize:12,color:"#065F46"}}>
            ✅ Notifications email actives — chaque réclamation enverra un email aux admins via Formspree.
          </div>
          <h4 style={{margin:"0 0 10px",color:DARK,fontSize:14}}>Ajouter un administrateur</h4>
          <div style={{display:"flex",gap:8,marginBottom:6}}>
            <input value={newAdmin} onChange={e=>{setNewAdmin(e.target.value);setAdminMsg("");}} onKeyDown={e=>e.key==="Enter"&&addAdmin()} placeholder="prenom.nom@lydex-se.ma" style={{flex:1,padding:"10px 13px",borderRadius:9,border:`2px solid ${BORDER}`,fontSize:13.5,outline:"none",background:"#FAFAFA"}}/>
            <button onClick={addAdmin} style={{padding:"10px 16px",borderRadius:9,border:"none",background:`linear-gradient(135deg,${CYAN},${CYAN_DARK})`,color:"#fff",fontSize:13.5,fontWeight:700,cursor:"pointer"}}>+ Ajouter</button>
          </div>
          {adminMsg&&<p style={{margin:"0 0 14px",fontSize:12.5,color:adminMsg.startsWith("✓")?"#059669":"#DC2626"}}>{adminMsg}</p>}
          <h4 style={{margin:"20px 0 10px",color:DARK,fontSize:14}}>Administrateurs actifs ({admins.length})</h4>
          <div style={{display:"flex",flexDirection:"column",gap:7}}>
            {admins.map(a=>(
              <div key={a} style={{display:"flex",justifyContent:"space-between",alignItems:"center",background:"#fff",borderRadius:10,padding:"11px 13px",border:`1.5px solid ${BORDER}`}}>
                <div style={{display:"flex",alignItems:"center",gap:10}}>
                  <div style={{width:34,height:34,borderRadius:"50%",background:`linear-gradient(135deg,${CYAN},${CYAN_DARK})`,display:"flex",alignItems:"center",justifyContent:"center",color:"#fff",fontWeight:800,fontSize:13,flexShrink:0}}>{a[0].toUpperCase()}</div>
                  <div>
                    <div style={{fontSize:13,fontWeight:600,color:DARK}}>{a}</div>
                    {a===user&&<div style={{fontSize:10.5,color:"#059669",fontWeight:700}}>● Connecté</div>}
                  </div>
                </div>
                {a!==user&&<button onClick={()=>removeAdmin(a)} style={{background:"#FEE2E2",border:"none",color:"#DC2626",padding:"6px 11px",borderRadius:7,fontSize:11.5,fontWeight:700,cursor:"pointer"}}>Retirer</button>}
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

// ─── ROOT ─────────────────────────────────────────────────────────────────────
export default function App() {
  const [user,      setUser]      = useState(null);
  const [view,      setView]      = useState("form");
  const [lastClaim, setLastClaim] = useState(null);
  const admins = loadJSON(ADMINS_KEY, DEFAULT_ADMINS);

  const getZone = () => {
    try { return new URLSearchParams(window.location.search).get("zone")||""; }
    catch { return ""; }
  };

  if (!user) return <LoginPage onLogin={setUser}/>;

  return (
    <div style={{minHeight:"100vh",background:BG,fontFamily:"'Segoe UI',system-ui,sans-serif"}}>
      <style>{`
        @keyframes fadeUp{from{opacity:0;transform:translateY(14px)}to{opacity:1;transform:translateY(0)}}
        *{box-sizing:border-box}
        input,select,textarea,button{font-family:inherit}
      `}</style>

      {isAdmin(user,admins)?(
        <div style={{maxWidth:700,margin:"0 auto",padding:"20px 16px"}}>
          <AdminDashboard user={user} onLogout={()=>{setUser(null);setView("form");}}/>
        </div>
      ):(
        <div style={{maxWidth:480,margin:"0 auto",padding:"20px 16px"}}>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:16}}>
            <div style={{background:DARK,borderRadius:12,padding:"8px 16px",display:"inline-flex",alignItems:"center"}}>
              <LydexLogoLight height={30}/>
            </div>
            <div style={{textAlign:"right"}}>
              <div style={{fontSize:11,color:"#6B7280",maxWidth:170,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{user}</div>
              <button onClick={()=>setUser(null)} style={{background:"none",border:"none",cursor:"pointer",fontSize:11,color:"#DC2626",fontWeight:600,padding:0}}>Déconnexion</button>
            </div>
          </div>
          <div style={{background:"#fff",borderRadius:20,padding:"24px 20px",boxShadow:"0 4px 20px rgba(0,0,0,0.07)"}}>
            {view==="form"&&(
              <>
                <h2 style={{margin:"0 0 4px",color:DARK,fontSize:19,fontWeight:800}}>Nouvelle réclamation</h2>
                <p style={{margin:"0 0 20px",color:"#6B7280",fontSize:13}}>Lycée d'Excellence de Rabat</p>
                <ClaimForm user={user} preZone={getZone()} onSuccess={claim=>{setLastClaim(claim);setView("success");}}/>
              </>
            )}
            {view==="success"&&lastClaim&&(
              <SuccessPage claim={lastClaim} onNew={()=>setView("form")} onLogout={()=>{setUser(null);setView("form");}}/>
            )}
          </div>
          <p style={{textAlign:"center",marginTop:16,fontSize:11,color:"#9CA3AF"}}>
            © 2026 Lycée d'Excellence de Rabat — Tous droits réservés
          </p>
        </div>
      )}
    </div>
  );
}
